_PHONE_NUMBER_DELIMITERS_RE = re.compile(r'[\s\-.()]')
_PHONE_NUMBER_DIGITS_RE = re.compile(r'\+?\d+')

# national/international patterns for countries with dedicated support, numbers are matched after delimiters
# (spaces, dashes, dots, parentheses) have been stripped
_PHONE_NUMBER_COUNTRY_RULES = {
    'US': {
        'national': re.compile(r'^\d{10}$'),
        'international': re.compile(r'^\+1\d{10}$'),
    },
    'GB': {
        'national': re.compile(r'^0\d{9,10}$'),
        'international': re.compile(r'^\+44\d{9,10}$'),
    },
}

# fallback for countries without dedicated rules, and for the un-parameterised international check: `+` followed by
# a country code and 6-14 further digits (7-15 digits in total), per the general shape of E.164 numbers
_PHONE_NUMBER_GENERIC_INTERNATIONAL_RE = re.compile(r'^\+[1-9]\d{6,14}$')
# fallback for generic national numbers when no country is given
_PHONE_NUMBER_GENERIC_NATIONAL_RE = re.compile(r'^\d{7,14}$')


class IsPhoneNumber(DirtyEquals[str]):
    """
    A class that checks if a value is a valid phone number, optionally restricted to a specific country's format.
    """

    def __init__(self, country: Optional[str] = None):
        """
        Args:
            country: ISO 3166-1 alpha-2 country code (e.g. `'US'`, `'GB'`) to validate against. If omitted, generic
                national and international phone number formats are accepted. Countries without dedicated support
                fall back to generic international validation.

        ```py title="IsPhoneNumber"
        from dirty_equals import IsPhoneNumber

        assert '+1-555-123-4567' == IsPhoneNumber
        assert '555-123-4567' == IsPhoneNumber
        assert '555-123-4567' == IsPhoneNumber('US')
        assert '555-123-4567' != IsPhoneNumber('GB')
        assert '020 7946 0958' == IsPhoneNumber('GB')
        assert '+44 20 7946 0958' == IsPhoneNumber('GB')
        assert 5551234567 != IsPhoneNumber
        ```
        """
        self.country = country.upper() if country else None
        super().__init__(plain_repr('*') if country is None else country)

    def equals(self, other: Any) -> bool:
        if not isinstance(other, str):
            return False

        cleaned = _PHONE_NUMBER_DELIMITERS_RE.sub('', other)
        if not _PHONE_NUMBER_DIGITS_RE.fullmatch(cleaned):
            return False

        if self.country is None:
            return bool(
                _PHONE_NUMBER_GENERIC_INTERNATIONAL_RE.fullmatch(cleaned)
                or _PHONE_NUMBER_GENERIC_NATIONAL_RE.fullmatch(cleaned)
            )

        rules = _PHONE_NUMBER_COUNTRY_RULES.get(self.country)
        if rules is None:
            return bool(_PHONE_NUMBER_GENERIC_INTERNATIONAL_RE.fullmatch(cleaned))

        return bool(rules['national'].fullmatch(cleaned) or rules['international'].fullmatch(cleaned))

